import Vision
import AVFoundation
import Combine

class PoseDetector: ObservableObject {
    @Published var repCount = 0
    @Published var bodyVisible = false
    @Published var statusMessage = "Get ready..."

    private var smoothedMetric: CGFloat = 0.5
    private let alpha: CGFloat = 0.25

    private enum RepState { case idle, wentDown }
    private var state: RepState = .idle
    private var lastRepTime: Date = .distantPast
    private let cooldown: TimeInterval = 0.8

    private var metricHistory: [CGFloat] = []
    private let historySize = 60
    private let minRangeToCount: CGFloat = 0.08

    private var bodyFirstDetected: Date?
    private let setupDelay: TimeInterval = 2.0

    private var frameCount = 0

    func processFrame(_ sampleBuffer: CMSampleBuffer) {
        frameCount += 1
        if frameCount % 4 != 0 { return }

        let handler = VNImageRequestHandler(cmSampleBuffer: sampleBuffer, orientation: .right)
        let request = VNDetectHumanBodyPoseRequest()
        try? handler.perform([request])

        guard let obs = request.results?.first else {
            DispatchQueue.main.async { self.bodyVisible = false }
            return
        }
        DispatchQueue.main.async { self.bodyVisible = true }

        guard let leftShoulder = try? obs.recognizedPoint(.leftShoulder),
              let rightShoulder = try? obs.recognizedPoint(.rightShoulder),
              leftShoulder.confidence > 0.3, rightShoulder.confidence > 0.3 else { return }

        let rawMetric = (leftShoulder.location.y + rightShoulder.location.y) / 2.0
        smoothedMetric = alpha * rawMetric + (1 - alpha) * smoothedMetric

        let now = Date()
        if bodyFirstDetected == nil { bodyFirstDetected = now }

        if now.timeIntervalSince(bodyFirstDetected!) < setupDelay {
            DispatchQueue.main.async { self.statusMessage = "Get ready..." }
            return
        }

        metricHistory.append(smoothedMetric)
        if metricHistory.count > historySize {
            metricHistory.removeFirst()
        }

        guard metricHistory.count >= 10 else { return }

        let windowMin = metricHistory.min()!
        let windowMax = metricHistory.max()!
        let range = windowMax - windowMin

        if range < minRangeToCount {
            DispatchQueue.main.async { self.statusMessage = "Start moving..." }
            return
        }

        DispatchQueue.main.async { self.statusMessage = "" }

        let downThreshold = windowMin + range * 0.35
        let upThreshold = windowMax - range * 0.35

        switch state {
        case .idle:
            if smoothedMetric < downThreshold { state = .wentDown }
        case .wentDown:
            if smoothedMetric > upThreshold && now.timeIntervalSince(lastRepTime) > cooldown {
                lastRepTime = now
                DispatchQueue.main.async { self.repCount += 1 }
                state = .idle
            }
        }
    }

    func reset() {
        repCount = 0
        state = .idle
        smoothedMetric = 0.5
        metricHistory = []
        bodyFirstDetected = nil
        statusMessage = "Get ready..."
    }
}

