import Foundation
import Combine

class WorkoutStore: ObservableObject {
    @Published var entries: [WorkoutEntry] = []
    @Published var dailyGoal: Int = 50

    private let entriesKey = "pushup_entries"
    private let goalKey = "pushup_daily_goal"

    init() {
        load()
    }

    func save() {
        if let data = try? JSONEncoder().encode(entries) {
            UserDefaults.standard.set(data, forKey: entriesKey)
        }
        UserDefaults.standard.set(dailyGoal, forKey: goalKey)
    }

    func load() {
        if let data = UserDefaults.standard.data(forKey: entriesKey),
           let decoded = try? JSONDecoder().decode([WorkoutEntry].self, from: data) {
            entries = decoded
        }
        let saved = UserDefaults.standard.integer(forKey: goalKey)
        dailyGoal = saved > 0 ? saved : 50
    }

    func addEntry(reps: Int, date: Date = Date()) {
        let entry = WorkoutEntry(date: date, reps: reps)
        entries.append(entry)
        save()
    }

    func todayTotal() -> Int {
        let cal = Calendar.current
        return entries
            .filter { cal.isDateInToday($0.date) }
            .reduce(0) { $0 + $1.reps }
    }

    func totalForDate(_ date: Date) -> Int {
        let cal = Calendar.current
        return entries
            .filter { cal.isDate($0.date, inSameDayAs: date) }
            .reduce(0) { $0 + $1.reps }
    }

    func last7Days() -> [(date: Date, total: Int)] {
        let cal = Calendar.current
        return (0..<7).reversed().compactMap { offset -> (date: Date, total: Int)? in
            guard let date = cal.date(byAdding: .day, value: -offset, to: Date()) else { return nil }
            return (date: date, total: totalForDate(date))
        }
    }

    func allTimeTotal() -> Int {
        entries.reduce(0) { $0 + $1.reps }
    }

    func bestDay() -> Int {
        guard !entries.isEmpty else { return 0 }
        let cal = Calendar.current
        var byDay: [String: Int] = [:]
        for e in entries {
            let key = cal.startOfDay(for: e.date).description
            byDay[key, default: 0] += e.reps
        }
        return byDay.values.max() ?? 0
    }

    func currentStreak() -> Int {
        let cal = Calendar.current
        var streak = 0
        var checkDate = cal.startOfDay(for: Date())
        while true {
            let total = totalForDate(checkDate)
            if total > 0 {
                streak += 1
                checkDate = cal.date(byAdding: .day, value: -1, to: checkDate) ?? checkDate
            } else {
                break
            }
        }
        return streak
    }
}

