import SwiftUI
import AVFoundation

struct WorkoutView: View {
    @EnvironmentObject var store: WorkoutStore
    @StateObject private var cameraManager = CameraManager()
    @StateObject private var poseDetector = PoseDetector()

    @State private var isWorkoutActive = false
    @State private var showEndSheet = false
    @State private var finalReps = 0
    @State private var pulseCounter = false

    var body: some View {
        ZStack {
            if cameraManager.permissionDenied {
                permissionDeniedView
            } else if !cameraManager.isCameraAvailable {
                cameraUnavailableView
            } else {
                cameraOverlayView
            }
        }
        .onAppear {
            cameraManager.checkPermission()
            cameraManager.onFrame = { buffer in
                poseDetector.processFrame(buffer)
            }
        }
        .onDisappear {
            cameraManager.stopSession()
            if isWorkoutActive {
                endWorkout()
            }
        }
        .sheet(isPresented: $showEndSheet) {
            WorkoutSummarySheet(reps: finalReps, onDismiss: {
                showEndSheet = false
                poseDetector.reset()
            })
            .environmentObject(store)
        }
    }

    // MARK: - Camera Overlay
    var cameraOverlayView: some View {
        ZStack {
            CameraPreviewView(session: cameraManager.session)
                .ignoresSafeArea()

            // Dark gradient at top
            LinearGradient(
                colors: [Color.black.opacity(0.65), Color.clear, Color.clear, Color.black.opacity(0.7)],
                startPoint: .top,
                endPoint: .bottom
            )
            .ignoresSafeArea()

            VStack {
                // Top bar
                HStack {
                    if isWorkoutActive {
                        Text("PUSHUPS")
                            .font(.caption)
                            .fontWeight(.bold)
                            .foregroundStyle(.white.opacity(0.7))
                            .tracking(3)
                    } else {
                        Text("PUSHUP TRACKER")
                            .font(.caption)
                            .fontWeight(.bold)
                            .foregroundStyle(.white.opacity(0.7))
                            .tracking(3)
                    }

                    Spacer()

                    Button(action: { cameraManager.flipCamera() }) {
                        Image(systemName: "camera.rotate.fill")
                            .font(.title2)
                            .foregroundStyle(.white)
                            .padding(12)
                            .background(.ultraThinMaterial, in: Circle())
                    }
                }
                .padding(.horizontal, 20)
                .padding(.top, 8)

                Spacer()

                // Rep counter (center)
                if isWorkoutActive {
                    VStack(spacing: 4) {
                        Text("\(poseDetector.repCount)")
                            .font(.system(size: 130, weight: .black, design: .rounded))
                            .foregroundStyle(.white)
                            .shadow(color: .black.opacity(0.5), radius: 8, x: 0, y: 4)
                            .scaleEffect(pulseCounter ? 1.08 : 1.0)
                            .animation(.spring(response: 0.25, dampingFraction: 0.5), value: pulseCounter)
                            .onChange(of: poseDetector.repCount) { _, _ in
                                pulseCounter = true
                                DispatchQueue.main.asyncAfter(deadline: .now() + 0.2) {
                                    pulseCounter = false
                                }
                            }

                        if !poseDetector.statusMessage.isEmpty {
                            Text(poseDetector.statusMessage)
                                .font(.subheadline)
                                .fontWeight(.semibold)
                                .foregroundStyle(.white.opacity(0.85))
                                .padding(.horizontal, 16)
                                .padding(.vertical, 6)
                                .background(.ultraThinMaterial, in: Capsule())
                        }

                        if !poseDetector.bodyVisible && isWorkoutActive {
                            HStack(spacing: 6) {
                                Image(systemName: "exclamationmark.triangle.fill")
                                    .foregroundStyle(.yellow)
                                Text("Body not in frame")
                                    .foregroundStyle(.white)
                            }
                            .font(.caption)
                            .fontWeight(.semibold)
                            .padding(.horizontal, 14)
                            .padding(.vertical, 6)
                            .background(Color.black.opacity(0.45), in: Capsule())
                        }
                    }
                } else {
                    VStack(spacing: 12) {
                        Image(systemName: "figure.strengthtraining.traditional")
                            .font(.system(size: 52))
                            .foregroundStyle(.white.opacity(0.85))

                        Text("Ready to train?")
                            .font(.title2)
                            .fontWeight(.bold)
                            .foregroundStyle(.white)

                        Text("Place your phone where it can\nsee your whole body")
                            .font(.subheadline)
                            .foregroundStyle(.white.opacity(0.7))
                            .multilineTextAlignment(.center)
                    }
                }

                Spacer()

                // Bottom controls
                HStack(spacing: 24) {
                    if isWorkoutActive {
                        // Manual +1
                        Button(action: {
                            poseDetector.repCount += 1
                        }) {
                            VStack(spacing: 4) {
                                Image(systemName: "plus.circle.fill")
                                    .font(.title)
                                Text("+1")
                                    .font(.caption)
                                    .fontWeight(.semibold)
                            }
                            .foregroundStyle(.white)
                            .frame(width: 72, height: 72)
                            .background(.ultraThinMaterial, in: RoundedRectangle(cornerRadius: 16))
                        }

                        // End workout
                        Button(action: endWorkout) {
                            Text("End")
                                .font(.title2)
                                .fontWeight(.bold)
                                .foregroundStyle(.white)
                                .frame(width: 120, height: 72)
                                .background(
                                    LinearGradient(colors: [Color.red.opacity(0.85), Color.red],
                                                   startPoint: .top, endPoint: .bottom),
                                    in: RoundedRectangle(cornerRadius: 20)
                                )
                                .shadow(color: .red.opacity(0.4), radius: 10, x: 0, y: 4)
                        }

                        // Reset
                        Button(action: {
                            poseDetector.repCount = 0
                        }) {
                            VStack(spacing: 4) {
                                Image(systemName: "arrow.counterclockwise")
                                    .font(.title)
                                Text("Reset")
                                    .font(.caption)
                                    .fontWeight(.semibold)
                            }
                            .foregroundStyle(.white)
                            .frame(width: 72, height: 72)
                            .background(.ultraThinMaterial, in: RoundedRectangle(cornerRadius: 16))
                        }
                    } else {
                        // Start
                        Button(action: startWorkout) {
                            HStack(spacing: 10) {
                                Image(systemName: "play.fill")
                                Text("Start Workout")
                                    .fontWeight(.bold)
                            }
                            .font(.title3)
                            .foregroundStyle(.white)
                            .frame(maxWidth: .infinity)
                            .frame(height: 64)
                            .background(
                                LinearGradient(colors: [Color.orange, Color.red],
                                               startPoint: .leading, endPoint: .trailing),
                                in: RoundedRectangle(cornerRadius: 20)
                            )
                            .shadow(color: .orange.opacity(0.4), radius: 12, x: 0, y: 5)
                        }
                        .padding(.horizontal, 32)
                    }
                }
                .padding(.horizontal, 24)
                .padding(.bottom, 32)
            }
        }
    }

    // MARK: - Permission Denied View
    var permissionDeniedView: some View {
        ZStack {
            LinearGradient(colors: [Color(red: 0.1, green: 0.05, blue: 0.02), Color(red: 0.2, green: 0.1, blue: 0.05)],
                           startPoint: .top, endPoint: .bottom)
                .ignoresSafeArea()

            VStack(spacing: 24) {
                Image(systemName: "camera.slash.fill")
                    .font(.system(size: 64))
                    .foregroundStyle(.orange.opacity(0.8))

                Text("Camera Access Required")
                    .font(.title2)
                    .fontWeight(.bold)
                    .foregroundStyle(.white)

                Text("Pushup Tracker uses the camera to detect your movements and count reps in real time.")
                    .font(.body)
                    .foregroundStyle(.white.opacity(0.7))
                    .multilineTextAlignment(.center)
                    .padding(.horizontal, 32)

                Button(action: openSettings) {
                    Text("Open Settings")
                        .fontWeight(.semibold)
                        .foregroundStyle(.white)
                        .frame(width: 200, height: 52)
                        .background(Color.orange, in: RoundedRectangle(cornerRadius: 16))
                }
            }
            .padding()
        }
    }

    // MARK: - Camera Unavailable
    var cameraUnavailableView: some View {
        ZStack {
            Color(red: 0.08, green: 0.06, blue: 0.04)
                .ignoresSafeArea()

            VStack(spacing: 20) {
