import SwiftUI

struct GoalsView: View {
    @EnvironmentObject var store: WorkoutStore
    @State private var editingGoal = false
    @State private var draftGoal: Double = 50

    private var todayTotal: Int { store.todayTotal() }
    private var goal: Int { store.dailyGoal }
    private var progress: Double { min(Double(todayTotal) / Double(goal), 1.0) }
    private var remaining: Int { max(goal - todayTotal, 0) }
    private var exceeded: Bool { todayTotal >= goal }

    var body: some View {
        NavigationStack {
            ZStack {
                LinearGradient(
                    colors: [Color(red: 0.07, green: 0.05, blue: 0.02), Color(red: 0.13, green: 0.07, blue: 0.02)],
                    startPoint: .top, endPoint: .bottom
                )
                .ignoresSafeArea()

                ScrollView {
                    VStack(spacing: 24) {
                        // Today's Goal Card
                        VStack(spacing: 20) {
                            HStack {
                                VStack(alignment: .leading, spacing: 4) {
                                    Text("Daily Goal")
                                        .font(.caption)
                                        .fontWeight(.semibold)
                                        .foregroundStyle(.white.opacity(0.6))
                                        .tracking(2)
                                        .textCase(.uppercase)

                                    Text("\(goal) pushups")
                                        .font(.title2)
                                        .fontWeight(.bold)
                                        .foregroundStyle(.white)
                                }

                                Spacer()

                                Button(action: {
                                    draftGoal = Double(goal)
                                    editingGoal = true
                                }) {
                                    Image(systemName: "pencil.circle.fill")
                                        .font(.title2)
                                        .foregroundStyle(.orange)
                                }
                            }

                            // Large circular progress
                            ZStack {
                                Circle()
                                    .stroke(Color.white.opacity(0.1), lineWidth: 16)

                                Circle()
                                    .trim(from: 0, to: progress)
                                    .stroke(
                                        LinearGradient(colors: [.orange, .red],
                                                       startPoint: .topLeading, endPoint: .bottomTrailing),
                                        style: StrokeStyle(lineWidth: 16, lineCap: .round)
                                    )
                                    .rotationEffect(.degrees(-90))
                                    .animation(.spring(response: 0.6, dampingFraction: 0.7), value: progress)

                                VStack(spacing: 4) {
                                    Text("\(todayTotal)")
                                        .font(.system(size: 52, weight: .black, design: .rounded))
                                        .foregroundStyle(.white)

                                    Text("of \(goal)")
                                        .font(.subheadline)
                                        .foregroundStyle(.white.opacity(0.5))
                                }
                            }
                            .frame(width: 180, height: 180)

                            // Status message
                            HStack(spacing: 8) {
                                Image(systemName: exceeded ? "checkmark.circle.fill" : "flame.fill")
                                    .foregroundStyle(exceeded ? .green : .orange)

                                Text(exceeded
                                     ? "Goal crushed! Great work!"
                                     : "\(remaining) more to hit your goal")
                                    .font(.subheadline)
                                    .fontWeight(.semibold)
                                    .foregroundStyle(.white.opacity(0.85))
                            }
                            .padding(.horizontal, 18)
                            .padding(.vertical, 10)
                            .background(
                                (exceeded ? Color.green : Color.orange).opacity(0.15),
                                in: Capsule()
                            )
                        }
                        .padding(24)
                        .background(Color.white.opacity(0.08), in: RoundedRectangle(cornerRadius: 24))
                        .padding(.horizontal, 16)

                        // Progress bar breakdown
                        VStack(alignment: .leading, spacing: 16) {
                            Text("Today's Progress")
                                .font(.title3)
                                .fontWeight(.bold)
                                .foregroundStyle(.white)

                            ProgressBarRow(
                                label: "Completed",
                                value: todayTotal,
                                total: goal,
                                color: .orange
                            )

                            ProgressBarRow(
                                label: "Remaining",
                                value: remaining,
                                total: goal,
                                color: .white.opacity(0.3)
                            )

                            // Percentage
                            HStack {
                                Text("Completion")
                                    .font(.subheadline)
                                    .foregroundStyle(.white.opacity(0.6))
                                Spacer()
                                Text("\(Int(progress * 100))%")
                                    .font(.title3)
                                    .fontWeight(.bold)
                                    .foregroundStyle(exceeded ? .green : .orange)
                            }
                        }
                        .padding(20)
                        .background(Color.white.opacity(0.07), in: RoundedRectangle(cornerRadius: 20))
                        .padding(.horizontal, 16)

                        // Weekly completion
                        WeeklyGoalGrid()
                    }
                    .padding(.vertical, 16)
                }
            }
            .navigationTitle("Goals")
            .navigationBarTitleDisplayMode(.large)
            .toolbarColorScheme(.dark, for: .navigationBar)
            .sheet(isPresented: $editingGoal) {
                GoalEditorSheet(goal: $store.dailyGoal, draft: $draftGoal, isPresented: $editingGoal)
            }
        }
    }
}

struct ProgressBarRow: View {
    let label: String
    let value: Int
    let total: Int
    let color: Color

    private var ratio: Double {
        total > 0 ? min(Double(value) / Double(total), 1.0) : 0
    }

    var body: some View {
        VStack(alignment: .leading, spacing: 6) {
            HStack {
                Text(label)
                    .font(.caption)
                    .foregroundStyle(.white.opacity(0.6))
                Spacer()
                Text("\(value)")
                    .font(.caption)
                    .fontWeight(.bold)
                    .foregroundStyle(.white)
            }

            GeometryReader { geo in
                ZStack(alignment: .leading) {
                    Capsule()
                        .fill(Color.white.opacity(0.1))
                        .frame(height: 10)

                    Capsule()
                        .fill(color)
                        .frame(width: geo.size.width * ratio, height: 10)
                        .animation(.spring(response: 0.5, dampingFraction: 0.7), value: ratio)
                }
            }
            .frame(height: 10)
        }
    }
}

struct WeeklyGoalGrid: View {
    @EnvironmentObject var store: WorkoutStore

    var weekData: [(date: Date, total: Int)] {
        store.last7Days()
    }

    var body: some View {
        VStack(alignment: .leading, spacing: 16) {
            Text("This Week")
                .font(.title3)
                .fontWeight(.bold)
                .foregroundStyle(.white)

            HStack(spacing: 8) {
                ForEach(weekData, id: \.date) { day in
                    let hit = day.total >= store.dailyGoal
                    let ratio = min(Double(day.total) / Double(store.dailyGoal), 1.0)

                    VStack(spacing: 6) {
                        Text(dayLetter(day.date))
                            .font(.caption2)
                            .fontWeight(.bold)
                            .foregroundStyle(.white.opacity(0.5))

                        ZStack(alignment: .bottom) {
                            RoundedRectangle(cornerRadius: 6)
                                .fill(Color.white.opacity(0.08))
                                .frame(height: 60)

                            RoundedRectangle(cornerRadius: 6)
                                .fill(
                                    hit
                                    ? LinearGradient(colors: [.green, .mint], startPoint: .bottom, endPoint: .top)
                                    : LinearGradient(colors: [.orange.opacity(0.7), .orange.opacity(0.4)],
                                                     startPoint: .bottom, endPoint: .top)
                                )
                                .frame(height: max(CGFloat(ratio) * 60, day.total > 0 ? 6 : 0))
                        }
                        .frame(height: 60)
                        .clipShape(RoundedRectangle(cornerRadius: 6))

                        Text(day.total > 0 ? "\(day.total)" : "-")
                            .font(.caption2)
                            .fontWeight(.semibold)
                            .foregroundStyle(.white.opacity(0.7))
                    }
                    .frame(maxWidth: .infinity)
                }
            }
        }
        .padding(20)
        .background(Color.white.opacity(0.07), in: RoundedRectangle(cornerRadius: 20))
        .padding(.horizontal, 16)
    }

    func dayLetter(_ date: Date) -> String {
        let formatter = DateFormatter()
        formatter.dateFormat = "EEE"
        return String(formatter.string(from: date).prefix(1))
    }
}

