import SwiftUI

struct StatsView: View {
    @EnvironmentObject var store: WorkoutStore

    var body: some View {
        NavigationStack {
            ZStack {
                LinearGradient(
                    colors: [Color(red: 0.07, green: 0.05, blue: 0.02), Color(red: 0.12, green: 0.07, blue: 0.02)],
                    startPoint: .top, endPoint: .bottom
                )
                .ignoresSafeArea()

                ScrollView {
                    VStack(spacing: 20) {
                        // Trophy Banner
                        HStack(spacing: 20) {
                            Image(systemName: "trophy.fill")
                                .font(.system(size: 44))
                                .foregroundStyle(.orange)

                            VStack(alignment: .leading, spacing: 4) {
                                Text("Your Progress")
                                    .font(.caption)
                                    .fontWeight(.semibold)
                                    .foregroundStyle(.white.opacity(0.5))
                                    .tracking(2)
                                    .textCase(.uppercase)

                                Text(rankTitle())
                                    .font(.title2)
                                    .fontWeight(.bold)
                                    .foregroundStyle(.white)
                            }
                        }
                        .frame(maxWidth: .infinity, alignment: .leading)
                        .padding(24)
                        .background(
                            LinearGradient(colors: [Color.orange.opacity(0.2), Color.red.opacity(0.1)],
                                           startPoint: .topLeading, endPoint: .bottomTrailing),
                            in: RoundedRectangle(cornerRadius: 20)
                        )
                        .padding(.horizontal, 16)

                        // Stats grid
                        LazyVGrid(columns: [GridItem(.flexible()), GridItem(.flexible())], spacing: 16) {
                            StatCard(
                                title: "All-Time Total",
                                value: "\(store.allTimeTotal())",
                                unit: "reps",
                                icon: "sum",
                                color: .orange
                            )

                            StatCard(
                                title: "Best Day",
                                value: "\(store.bestDay())",
                                unit: "reps",
                                icon: "star.fill",
                                color: .yellow
                            )

                            StatCard(
                                title: "Current Streak",
                                value: "\(store.currentStreak())",
                                unit: store.currentStreak() == 1 ? "day" : "days",
                                icon: "flame.fill",
                                color: .red
                            )

                            StatCard(
                                title: "Total Sessions",
                                value: "\(store.entries.count)",
                                unit: store.entries.count == 1 ? "session" : "sessions",
                                icon: "calendar.badge.checkmark",
                                color: .mint
                            )
                        }
                        .padding(.horizontal, 16)

                        // Average section
                        VStack(alignment: .leading, spacing: 14) {
                            Text("Averages")
                                .font(.title3)
                                .fontWeight(.bold)
                                .foregroundStyle(.white)

                            averageRow(label: "Per session", value: avgPerSession())
                            averageRow(label: "Per active day", value: avgPerDay())
                        }
                        .padding(20)
                        .background(Color.white.opacity(0.07), in: RoundedRectangle(cornerRadius: 20))
                        .padding(.horizontal, 16)

                        // Milestones
                        VStack(alignment: .leading, spacing: 14) {
                            Text("Milestones")
                                .font(.title3)
                                .fontWeight(.bold)
                                .foregroundStyle(.white)

                            ForEach(milestones(), id: \.0) { milestone in
                                MilestoneRow(
                                    name: milestone.0,
                                    target: milestone.1,
                                    current: store.allTimeTotal()
                                )
                            }
                        }
                        .padding(20)
                        .background(Color.white.opacity(0.07), in: RoundedRectangle(cornerRadius: 20))
                        .padding(.horizontal, 16)

                        if store.entries.isEmpty {
                            VStack(spacing: 14) {
                                Image(systemName: "figure.strengthtraining.traditional")
                                    .font(.system(size: 48))
                                    .foregroundStyle(.orange.opacity(0.5))
                                Text("No workouts recorded yet")
                                    .font(.headline)
                                    .foregroundStyle(.white.opacity(0.5))
                                Text("Head to Workout to start tracking")
                                    .font(.subheadline)
                                    .foregroundStyle(.white.opacity(0.35))
                            }
                            .frame(maxWidth: .infinity)
                            .padding(.vertical, 32)
                        }
                    }
                    .padding(.vertical, 16)
                }
            }
            .navigationTitle("Stats")
            .navigationBarTitleDisplayMode(.large)
            .toolbarColorScheme(.dark, for: .navigationBar)
        }
    }

    func avgPerSession() -> String {
        guard !store.entries.isEmpty else { return "0" }
        let avg = Double(store.allTimeTotal()) / Double(store.entries.count)
        return String(format: "%.1f", avg)
    }

    func avgPerDay() -> String {
        let data = store.last7Days().filter { $0.total > 0 }
        guard !data.isEmpty else { return "0" }
        let avg = Double(data.reduce(0) { $0 + $1.total }) / Double(data.count)
        return String(format: "%.1f", avg)
    }

    func rankTitle() -> String {
        let total = store.allTimeTotal()
        switch total {
        case 0: return "Beginner"
        case 1..<50: return "Rookie"
        case 50..<150: return "Athlete"
        case 150..<500: return "Warrior"
        case 500..<1000: return "Elite"
        default: return "Legend"
        }
    }

    func milestones() -> [(String, Int)] {
        [
            ("First 10", 10),
            ("Fifty Club", 50),
            ("Century Mark", 100),
            ("Iron 500", 500),
            ("Legendary 1000", 1000),
        ]
    }

    func averageRow(label: String, value: String) -> some View {
        HStack {
            Text(label)
                .font(.subheadline)
