struct MilestoneRow: View {
    let name: String
    let target: Int
    let current: Int

    private var progress: Double { min(Double(current) / Double(target), 1.0) }
    private var achieved: Bool { current >= target }

    var body: some View {
        VStack(alignment: .leading, spacing: 6) {
            HStack {
                Image(systemName: achieved ? "checkmark.circle.fill" : "circle")
                    .foregroundStyle(achieved ? .green : .white.opacity(0.3))
                    .font(.subheadline)

                Text(name)
                    .font(.subheadline)
                    .fontWeight(.semibold)
                    .foregroundStyle(achieved ? .white : .white.opacity(0.7))

                Spacer()

                Text("\(min(current, target)) / \(target)")
                    .font(.caption)
                    .foregroundStyle(.white.opacity(0.5))
            }

            GeometryReader { geo in
                ZStack(alignment: .leading) {
                    Capsule()
                        .fill(Color.white.opacity(0.08))
                        .frame(height: 6)

                    Capsule()
                        .fill(achieved ? Color.green : Color.orange)
                        .frame(width: geo.size.width * progress, height: 6)
                        .animation(.spring(response: 0.5, dampingFraction: 0.7), value: progress)
                }
            }
            .frame(height: 6)
        }
    }
}

